"},{"name":"Post Plan on PR","id":"terraform_plan_comment","uses":"actions/github-script@v6","if":"github.event_name == 'pull_request'","with":{"script":"const fs = require('fs');
const output = fs.readFileSync('${{ env.TEMPLATE_DIR }}/plan_output_multiline.txt', 'utf8');
const { data: comments } = await github.rest.issues.listComments({
  owner: context.repo.owner,
  repo: context.repo.repo,
  issue_number: context.issue.number
})
const botComment = comments.find(comment => {
  return comment.user.type === 'Bot' && comment.body.includes('Terraform Plan')
})
const commentBody = `#### Terraform Plan 📖
<details>
<summary>Terraform Plan for '${{ env.API_NAME }}'</summary>

\`\`\`hcl
${output}
\`\`\`
</details>
`;
if (botComment) {
  await github.rest.issues.updateComment({
    owner: context.repo.owner,
    repo: context.repo.repo,
    body: commentBody,
    comment_id: botComment.id
  })
} else {
  await github.rest.issues.createComment({
    owner: context.repo.owner,
    repo: context.repo.repo,
    body: commentBody,
    issue_number: context.issue.number
  })
}
